package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.APKConstant2;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.service.APKConstant2Service;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedApkConstant2Service implements CachedService, APKConstant2Service {

    @Autowired
    private APKConstant2Service apkConstant2Service;

    private static final ThreadLocal<CachedApkConstant2Buffer> BUFFER = new ThreadLocal<>();

    public CachedApkConstant2Service() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public APKConstant2 getByKey(Pensioenstelsel pensioenStelsel, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedapkConstant2Service.getByKey");
        CachedApkConstant2Buffer buffer = CachedApkConstant2Service.getBuffer();
        List<APKConstant2> results = buffer.get(pensioenStelsel);
        if (results == null) {
            results = apkConstant2Service.findByKey(pensioenStelsel);
            buffer.put(pensioenStelsel, results);
        }
        APKConstant2 result = zoekLijst(results, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }


    private APKConstant2 zoekLijst(List<APKConstant2> lijst, LocalDate datum) {
        APKConstant2 result = null;
        for (APKConstant2 constant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(constant.getBeginDatum(), constant.getEindDatum());
            if (periode.contains(datum)) {
                result = constant;
                break;
            }
        }
        return result;
    }

    @Override
    public void clearCache() {
        CachedApkConstant2Service.getBuffer().clear();
    }

    private static class CachedApkConstant2Buffer {

        private final Map<Pensioenstelsel, List<APKConstant2>> apkConstant2Buffer = new HashMap<>();

        public List<APKConstant2> get(Pensioenstelsel key) {
            return apkConstant2Buffer.get(key);
        }

        public void put(Pensioenstelsel key, List<APKConstant2> lijst) {
            apkConstant2Buffer.put(key, lijst);
        }

        public void clear() {
            apkConstant2Buffer.clear();
        }
    }

    private static CachedApkConstant2Buffer getBuffer() {
        CachedApkConstant2Buffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedApkConstant2Buffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<APKConstant2> findByKey(Pensioenstelsel pensioenStelsel) {
        return apkConstant2Service.findByKey(pensioenStelsel);
    }


    @Override
    public List<APKConstant2> findAll() {
        return apkConstant2Service.findAll();
    }

    @Override
    public APKConstant2 create(APKConstant2 constant) {
        return apkConstant2Service.create(constant);
    }

    @Override
    public void update(APKConstant2 constant) {
        apkConstant2Service.update(constant);
    }

    @Override
    public void delete(APKConstant2 constant) {
        apkConstant2Service.delete(constant);
    }

    @Override
    public APKConstant2 getById(Integer id) {
        return apkConstant2Service.getById(id);
    }

    @Override
    public APKConstant2 getById(Integer id, String fetchFields) {
        return apkConstant2Service.getById(id, fetchFields);
    }

    @Override
    public APKConstant2 getByCriteria(CriteriaBuilder cb) {
        return apkConstant2Service.getByCriteria(cb);
    }


    @Override
    public List<APKConstant2> findAll(String fetchFields) {
        return apkConstant2Service.findAll(fetchFields);
    }

    @Override
    public List<APKConstant2> findByCriteria(CriteriaBuilder cb) {
        return apkConstant2Service.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return apkConstant2Service.countByCriteria(cb);
    }

    @Override
    public Map<Integer, APKConstant2> cacheByCriteria(CriteriaBuilder cb) {
        return apkConstant2Service.cacheByCriteria(cb);
    }

    @Override
    public APKConstant2 getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkConstant2Service.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<APKConstant2> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkConstant2Service.findByCriteriaTemporalFree(cb);
    }
}
